parameters.jsCode:
return [{
  json: {
    workflow_id: 'CWF-310',
    vein: 'context_engineering_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    final_script_packet: $json.final_script_packet || {},
    target_platform: $json.target_platform || ($json.final_script_packet && $json.final_script_packet.payload && $json.final_script_packet.payload.context && $json.final_script_packet.payload.context.target_platform) || 'youtube',
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString()
  }
}];

const fsp = $json.final_script_packet || {};
const payload = fsp.payload || {};

const validationErrors = [];
if (!fsp.instance_id && !fsp.packet_id) validationErrors.push('final_script_packet missing instance_id/packet_id');
if (!payload.narrative) validationErrors.push('final_script_packet missing narrative section');
if (!payload.quality) validationErrors.push('final_script_packet missing quality section');
if (!payload.status) validationErrors.push('final_script_packet missing status section');

if (validationErrors.length > 0) {
  throw new Error('CWF-310 input validation failed: ' + validationErrors.join('; '));
}

return [{
  json: {
    ...$json,
    input_validation: 'PASSED',
    source_packet_id: fsp.instance_id || fsp.packet_id || 'UNKNOWN',
    script_quality: payload.quality || {}
  }
}];

const platform = $json.target_platform || 'youtube';

const platformToolSets = {
  youtube: {
    allowed: ['voice_performer', 'video_editor', 'caption_generator', 'thumbnail_creator', 'seo_metadata_updater', 'chapter_marker_inserter', 'end_screen_composer'],
    forbidden: ['content_modifier', 'brand_deviator', 'unsupervised_publisher', 'script_rewriter']
  },
  blog: {
    allowed: ['markdown_formatter', 'seo_metadata_updater', 'featured_image_generator', 'internal_link_mapper', 'readability_scorer'],
    forbidden: ['content_modifier', 'brand_deviator', 'unsupervised_publisher', 'script_rewriter']
  },
  podcast: {
    allowed: ['voice_performer', 'audio_editor', 'transcript_generator', 'chapter_marker_inserter', 'rss_packager'],
    forbidden: ['content_modifier', 'brand_deviator', 'unsupervised_publisher', 'video_editor']
  },
  email: {
    allowed: ['markdown_formatter', 'seo_metadata_updater', 'cta_optimizer', 'subject_line_tester'],
    forbidden: ['content_modifier', 'brand_deviator', 'unsupervised_publisher', 'video_editor']
  }
};

const toolSet = platformToolSets[platform] || platformToolSets['youtube'];

return [{
  json: {
    ...$json,
    resolved_tool_set: {
      platform: platform,
      allowed_tools: toolSet.allowed,
      forbidden_tools: toolSet.forbidden,
      tool_resolution_timestamp: new Date().toISOString()
    }
  }
}];

const platform = $json.target_platform || 'youtube';
const scriptQuality = $json.script_quality || {};

const platformConstraints = {
  youtube: [
    'Script narrative integrity must be preserved in final video',
    'Voice/tone must match calibration profile from CWF-240',
    'Chapter markers required at every major section break',
    'Thumbnail must reference primary hook claim',
    'SEO metadata must be applied before upload',
    'Approval required before publishing'
  ],
  blog: [
    'Markdown formatting must be applied before CMS upload',
    'Featured image must be generated and attached',
    'Internal linking to at least 2 existing posts required',
    'Meta title under 60 characters',
    'Approval required before publishing'
  ],
  podcast: [
    'Audio must be mastered to -14 LUFS for streaming platforms',
    'Transcript must accompany audio file',
    'Chapter markers required in RSS feed',
    'Show notes must reference primary sources',
    'Approval required before publishing'
  ],
  email: [
    'Subject line under 50 characters for mobile preview',
    'CTA must appear above the fold',
    'Unsubscribe link required',
    'Plain text version required alongside HTML',
    'Approval required before sending'
  ]
};

const constraints = platformConstraints[platform] || platformConstraints['youtube'];

const qualityGates = {
  grammar_minimum: 0.95,
  seo_readiness_minimum: 0.85,
  voice_consistency_minimum: 0.90,
  current_grammar: scriptQuality.grammar_score || 0,
  current_seo: scriptQuality.seo_readiness || 0,
  current_voice: scriptQuality.tone_consistency || 0,
  gates_passed: (
    (scriptQuality.grammar_score || 0) >= 0.95 &&
    (scriptQuality.seo_readiness || 0) >= 0.85 &&
    (scriptQuality.tone_consistency || 0) >= 0.90
  )
};

return [{
  json: {
    ...$json,
    execution_constraints: constraints,
    quality_gates: qualityGates
  }
}];

const fsp = $json.final_script_packet || {};
const fspPayload = fsp.payload || {};
const toolSet = $json.resolved_tool_set || {};
const constraints = $json.execution_constraints || [];
const qualityGates = $json.quality_gates || {};

const executionContextPacket = {
  instance_id: 'ECP-' + Date.now(),
  artifact_family: 'execution_context_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-310-Execution-Context-Builder',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      content: fspPayload.narrative || {},
      source_script_id: $json.source_packet_id,
      content_fingerprint: 'SHA256-' + Math.random().toString(36).substr(2, 16)
    },
    context: {
      sourced_from_packet_id: $json.source_packet_id,
      target_platform: $json.target_platform,
      execution_requirements: {
        allowed_tools: toolSet.allowed_tools || [],
        forbidden_tools: toolSet.forbidden_tools || [],
        constraints: constraints,
        execution_mode: 'supervised',
        approval_required_before: 'publishing'
      }
    },
    evidence: {
      lineage_references: [
        { type: 'final_script_packet', id: $json.source_packet_id },
        { type: 'dossier', id: $json.dossier_id }
      ],
      validation_checks: [
        { check: 'input_validation', result: $json.input_validation },
        { check: 'quality_gates', result: qualityGates.gates_passed ? 'PASSED' : 'FAILED' }
      ]
    },
    quality: {
      context_build_readiness: qualityGates.gates_passed ? 0.95 : 0.60,
      gate_checks: qualityGates,
      execution_context_complete: true
    },
    status: {
      decision_path: qualityGates.gates_passed ? 'PROCEED_TO_CWF-320' : 'ESCALATE_TO_WF-900',
      next_workflow: 'CWF-320',
      escalation_needed: !qualityGates.gates_passed
    }
  }
};

return [{ json: executionContextPacket }];

const pkt = $json;
const payload = pkt.payload || {};

if (payload.status && payload.status.escalation_needed) {
  throw new Error('CWF-310 quality gates failed â€” routing to WF-900. Gates: ' + JSON.stringify(payload.quality.gate_checks));
}

return [{
  json: {
    workflow_id: 'CWF-310',
    execution_status: 'SUCCESS',
    execution_context_packet: pkt,
    next_workflow: 'CWF-320',
    dossier_delta: {
      namespace: 'context',
      mutation_type: 'append_to_array',
      target: 'dossier.context.execution_context_packets',
      value: {
        instance_id: pkt.instance_id,
        artifact_family: 'execution_context_packet',
        target_platform: payload.context && payload.context.target_platform,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-310',
        operation: 'CREATE_EXECUTION_CONTEXT_PACKET',
        sourced_from: pkt.dossier_ref
      }
    },
    runtime_delta: {
      namespace: 'runtime',
      mutation_type: 'append',
      target: 'dossier.runtime.context_build_log',
      value: {
        cwf310_executed: true,
        execution_context_id: pkt.instance_id,
        timestamp: new Date().toISOString()
      }
    },
    decision: 'PROCEED_TO_CWF-320'
  }
}];
